ALTER TABLE public.orders DROP CONSTRAINT IF EXISTS orders_status_check;
ALTER TABLE public.orders ADD CONSTRAINT orders_status_check CHECK (status = ANY (ARRAY['pending_approval'::text, 'pending'::text, 'in_production'::text, 'completed'::text, 'delivered'::text, 'overdue'::text, 'deleted'::text, 'cancelled'::text]));